'use client'

import React from "react"

import { ArrowLeft, Upload } from 'lucide-react'
import { useState } from 'react'
import { useRouter } from 'next/navigation'
import Header from '@/components/Header'
import Link from 'next/link'
import { useAuthContext } from '@/components/AuthProvider'
import { productService } from '@/lib/product-service'
import { toast } from 'sonner'

export default function AddProductPage() {
  const router = useRouter()
  const { token, user } = useAuthContext()
  const [isLoading, setIsLoading] = useState(false)
  const [formData, setFormData] = useState({
    name: '',
    category: '',
    description: '',
    price: '',
    unit: '',
    available_quantity: '',
    location: '',
    image_url: '',
  })

  const [imagePreview, setImagePreview] = useState<string | null>(null)

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement | HTMLSelectElement>) => {
    const { name, value } = e.target
    setFormData((prev) => ({
      ...prev,
      [name]: value,
    }))
  }

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0]
    if (file) {
      const reader = new FileReader()
      reader.onloadend = () => {
        const result = reader.result as string
        setImagePreview(result)
        setFormData(prev => ({ ...prev, image_url: result }))
      }
      reader.readAsDataURL(file)
    }
  }

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault()
    
    if (!token) {
      toast.error('Please login to create a product')
      router.push('/auth/login')
      return
    }

    if (user?.role !== 'farmer') {
      toast.error('Only farmers can create products')
      return
    }

    setIsLoading(true)

    try {
      const productData = {
        name: formData.name,
        category: formData.category,
        description: formData.description || undefined,
        price: parseFloat(formData.price),
        unit: formData.unit,
        available_quantity: parseInt(formData.available_quantity),
        location: formData.location || undefined,
        image_url: formData.image_url || undefined,
      }

      await productService.createProduct(productData, token)
      
      toast.success('Product created successfully!')
      
      router.push('/products')
    } catch (error) {
      console.error('Error creating product:', error)
      toast.error(error instanceof Error ? error.message : 'Failed to create product')
    } finally {
      setIsLoading(false)
    }
  }

  const categories = ['Vegetables', 'Fruits', 'Grains', 'Dairy', 'Spices', 'Others']
  const units = ['KG', 'Litre', 'Piece', 'Dozen', 'Ton', 'Bag']

  return (
    <div className="min-h-screen bg-background">
      <Header />

      <main className="mx-auto max-w-4xl px-4 py-8 sm:px-6 lg:px-8">
        {/* Back Button */}
        <Link
          href="/products"
          className="inline-flex items-center gap-2 text-primary hover:text-primary/90 transition-colors mb-6"
        >
          <ArrowLeft className="h-5 w-5" />
          Back to Products
        </Link>

        <div className="rounded-lg border border-border bg-card p-6 sm:p-8">
          <h1 className="text-3xl font-bold text-foreground">List a New Product</h1>
          <p className="mt-2 text-muted-foreground">Add your agricultural product to the marketplace</p>

          <form onSubmit={handleSubmit} className="mt-8 space-y-6">
            {/* Product Image Upload */}
            <div className="rounded-lg border-2 border-dashed border-border bg-secondary/50 p-8">
              <div className="flex flex-col items-center gap-4">
                {imagePreview ? (
                  <>
                    <img
                      src={imagePreview || "/placeholder.svg"}
                      alt="Preview"
                      className="h-32 w-32 rounded-lg object-cover"
                    />
                    <button
                      type="button"
                      onClick={() => setImagePreview(null)}
                      className="text-sm text-primary hover:text-primary/90 transition-colors"
                    >
                      Remove image
                    </button>
                  </>
                ) : (
                  <>
                    <Upload className="h-12 w-12 text-muted-foreground" />
                    <div className="text-center">
                      <label htmlFor="image-upload" className="cursor-pointer">
                        <span className="font-medium text-primary hover:text-primary/90 transition-colors">
                          Click to upload
                        </span>
                        <span className="text-muted-foreground"> or drag and drop</span>
                      </label>
                      <p className="mt-2 text-xs text-muted-foreground">PNG, JPG, GIF up to 10MB</p>
                    </div>
                    <input
                      id="image-upload"
                      type="file"
                      accept="image/*"
                      onChange={handleImageUpload}
                      className="hidden"
                    />
                  </>
                )}
              </div>
            </div>

            {/* Product Information */}
            <div className="space-y-4">
              <h2 className="text-lg font-semibold text-foreground">Product Information</h2>

              {/* Product Name */}
              <div>
                <label htmlFor="name" className="block text-sm font-medium text-foreground">
                  Product Name *
                </label>
                <input
                  id="name"
                  type="text"
                  name="name"
                  value={formData.name}
                  onChange={handleInputChange}
                  placeholder="e.g., Organic Tomatoes"
                  required
                  className="mt-2 w-full rounded-lg border border-border bg-background px-4 py-2 text-foreground placeholder-muted-foreground focus:outline-none focus:ring-2 focus:ring-primary"
                />
              </div>

              {/* Category and Unit */}
              <div className="grid gap-4 sm:grid-cols-2">
                <div>
                  <label htmlFor="category" className="block text-sm font-medium text-foreground">
                    Category *
                  </label>
                  <select
                    id="category"
                    name="category"
                    value={formData.category}
                    onChange={handleInputChange}
                    required
                    className="mt-2 w-full rounded-lg border border-border bg-background px-4 py-2 text-foreground focus:outline-none focus:ring-2 focus:ring-primary"
                  >
                    <option value="">Select a category</option>
                    {categories.map((cat) => (
                      <option key={cat} value={cat}>
                        {cat}
                      </option>
                    ))}
                  </select>
                </div>

                <div>
                  <label htmlFor="unit" className="block text-sm font-medium text-foreground">
                    Unit of Measurement *
                  </label>
                  <select
                    id="unit"
                    name="unit"
                    value={formData.unit}
                    onChange={handleInputChange}
                    required
                    className="mt-2 w-full rounded-lg border border-border bg-background px-4 py-2 text-foreground focus:outline-none focus:ring-2 focus:ring-primary"
                  >
                    <option value="">Select a unit</option>
                    {units.map((u) => (
                      <option key={u} value={u}>
                        {u}
                      </option>
                    ))}
                  </select>
                </div>
              </div>

              {/* Price and Quantity */}
              <div className="grid gap-4 sm:grid-cols-2">
                <div>
                  <label htmlFor="price" className="block text-sm font-medium text-foreground">
                    Price per Unit (ETB) *
                  </label>
                  <input
                    id="price"
                    type="number"
                    name="price"
                    value={formData.price}
                    onChange={handleInputChange}
                    placeholder="0.00"
                    step="0.01"
                    min="0"
                    required
                    disabled={isLoading}
                    className="mt-2 w-full rounded-lg border border-border bg-background px-4 py-2 text-foreground placeholder-muted-foreground focus:outline-none focus:ring-2 focus:ring-primary"
                  />
                </div>

                <div>
                  <label htmlFor="quantity" className="block text-sm font-medium text-foreground">
                    Quantity Available *
                  </label>
                  <input
                    id="quantity"
                    type="number"
                    name="available_quantity"
                    value={formData.available_quantity}
                    onChange={handleInputChange}
                    placeholder="0"
                    min="0"
                    required
                    disabled={isLoading}
                    className="mt-2 w-full rounded-lg border border-border bg-background px-4 py-2 text-foreground placeholder-muted-foreground focus:outline-none focus:ring-2 focus:ring-primary"
                  />
                </div>
              </div>

              {/* Location */}
              <div>
                <label htmlFor="location" className="block text-sm font-medium text-foreground">
                  Product Location *
                </label>
                <input
                  id="location"
                  type="text"
                  name="location"
                  value={formData.location}
                  onChange={handleInputChange}
                  placeholder="e.g., Addis Ababa, Hawassa, Jimma"
                  required
                  className="mt-2 w-full rounded-lg border border-border bg-background px-4 py-2 text-foreground placeholder-muted-foreground focus:outline-none focus:ring-2 focus:ring-primary"
                />
              </div>

              {/* Description */}
              <div>
                <label htmlFor="description" className="block text-sm font-medium text-foreground">
                  Product Description
                </label>
                <textarea
                  id="description"
                  name="description"
                  value={formData.description}
                  onChange={handleInputChange}
                  placeholder="Describe your product, quality, harvesting method, shelf life, etc."
                  rows={5}
                  className="mt-2 w-full rounded-lg border border-border bg-background px-4 py-2 text-foreground placeholder-muted-foreground focus:outline-none focus:ring-2 focus:ring-primary"
                />
              </div>
            </div>

            {/* Form Actions */}
            <div className="flex flex-col gap-3 sm:flex-row sm:justify-end">
              <Link
                href="/products"
                className="rounded-lg border border-border bg-secondary px-6 py-2 text-center font-medium text-foreground hover:bg-secondary/80 transition-colors"
              >
                Cancel
              </Link>
              <button
                type="submit"
                disabled={isLoading}
                className="rounded-lg bg-primary px-6 py-2 font-medium text-primary-foreground hover:bg-primary/90 transition-colors disabled:opacity-50 disabled:cursor-not-allowed"
              >
                {isLoading ? 'Publishing...' : 'Publish Product'}
              </button>
            </div>
          </form>
        </div>

        {/* Help Section */}
        <div className="mt-8 rounded-lg border border-border bg-card p-6">
          <h3 className="font-semibold text-foreground">Tips for a Successful Listing</h3>
          <ul className="mt-4 space-y-2 text-sm text-muted-foreground">
            <li>✓ Use clear, descriptive product names</li>
            <li>✓ Set competitive prices based on market rates</li>
            <li>✓ Be honest about quantity and quality</li>
            <li>✓ Upload a clear product image</li>
            <li>✓ Update availability regularly to keep buyers informed</li>
          </ul>
        </div>
      </main>
    </div>
  )
}
